const input = $input.first().json;
const job = input.job;
const ctx = input.ctx;
const profile = ctx.results?.career_goals || {};
const skills = ctx.results?.resume_profile?.skills_matrix || [];

// 1. Build prompt
const prompt = `You are an AI Matchmaker.

Candidate Role: ${profile.inferred_roles?.[0]}
Candidate Level: ${profile.experience_level}
Candidate Skills: ${skills.map(s => s.normalized).join(', ')}

Job Title: ${job.title}
Job Desc: ${job.description || 'Not provided'}`;

return [{
  json: {
    job,
    prompt,
    model: $env.MODEL_JOB_SCORING || 'anthropic/claude-haiku-3'
  }
}];

