const req = $('Prepare Prompt').item.json;
const llmRes = $input.first().json;

let score = 50;
let explanation = "Fallback score due to LLM error";

if (llmRes.choices && llmRes.choices.length > 0) {
  try {
    const parsed = JSON.parse(llmRes.choices[0].message.content);
    score = parsed.match_score || 50;
    explanation = parsed.match_explanation || "No explanation provided.";
  } catch (e) {}
}

req.job.enrichment = req.job.enrichment || {};
req.job.enrichment.match_score = score;
req.job.enrichment.match_explanation = explanation;
req.job.match_score = score; // for DB ease

return [{ json: req.job }];
